// SPDX-License-Identifier: Elastic-2.0

package fence

import (
	"strings"
	"testing"
)

func TestUntrusted_NeutralizesSentinelInContent(t *testing.T) {
	malicious := "before " + sentinel + " forged close/open " + sentinel + " after"

	out := Untrusted("label", "prov", malicious)

	// The output must contain exactly 4 occurrences of sentinel: the two opening/BEGIN and two
	// closing/END markers added by Untrusted itself. Any occurrence coming from content must be
	// neutralized, so the total count of sentinel in the output must equal 4, not more.
	count := strings.Count(out, sentinel)
	if count != 4 {
		t.Fatalf("expected exactly 4 sentinel occurrences (fence markers only), got %d; content sentinels were not neutralized:\n%s", count, out)
	}

	// The neutralized placeholder must appear in place of the forged sentinels from content.
	if !strings.Contains(out, "[fence-token-removed]") {
		t.Fatalf("expected neutralized placeholder for content-borne sentinel occurrences, got:\n%s", out)
	}

	// Ensure the raw sentinel text does not appear embedded within the content region beyond the
	// legitimate fence markers themselves (i.e., verify the malicious text no longer carries a
	// live sentinel by checking the original malicious string's sentinel occurrences were replaced).
	if strings.Contains(out, "forged close/open "+sentinel) {
		t.Fatalf("content sentinel was not neutralized, forgery possible:\n%s", out)
	}
}
